def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        usage_ratio = item / capacity
        penalty = 0
        if usage_ratio > 2:
            penalty += (usage_ratio - 2) ** 3 * 200
        elif usage_ratio > 1:
            penalty += (usage_ratio - 1) * 500
        elif usage_ratio == 1:
            penalty += 50
        if usage_ratio < 1:
            safe_margin = 1 - usage_ratio
            if safe_margin < 0.05:
                penalty += 20 / safe_margin
            else:
                penalty += 10 * np.exp(-10 * safe_margin)
        if capacity < 0.05:
            penalty += 100
        elif capacity < 0.5:
            penalty += 30
        priority_val = penalty
        log_component = np.log1p(capacity)
        if log_component < 0.5:
            priority_val += 5 * (0.5 - log_component)
        if i % 2 == 0:
            priority_val *= 1.1
        else:
            priority_val *= 0.9
        priorities[i] = priority_val
    min_priority = np.min(priorities)
    if min_priority < 1e-5:
        priorities += 1e-3
    for _ in range(2):
        for i in range(len(priorities)):
            if i > 0:
                priorities[i] = (priorities[i] + priorities[i - 1]) / 2
            if i < len(priorities) - 1:
                priorities[i] = (priorities[i] + priorities[i + 1]) / 2
    return priorities
